let valor = $('Input').first().json.MontoPago;
let referencia = $('Input').first().json.Referencia;

valor=valor*100;
id_trx = $input.first().json.IdPago;


return {
    amount: valor, 
    amountWithoutTax: valor, 
    clientTransactionId: id_trx,  
    currency: "USD",  
    storeId: "5b3febdd-9982-47e0-84b0-cbbcd62ae799",  
    reference: (referencia||'Reserva Tinkay')
}

// 1. Obtener el buffer del dato binario llamado 'Respuesta'
const buffer = await this.helpers.getBinaryDataBuffer(0, 'Respuesta');

// 2. Convertir a texto UTF-8
const text = buffer.toString('utf8');

try {
    // 3. Como Payphone devuelve un JSON, lo parseamos
    const jsonRes = JSON.parse(text);

    // 4. Extraemos la URL (Payphone suele usar la clave 'payPhoneUri')
    // Si no es un objeto, usamos el texto directamente
    const urlFinal = jsonRes.payPhoneUri || text;

    return [{
        json: {
            Respuesta: {
                PayphoneUrl: urlFinal.replace(/[\\"]/g, '').trim(),      
            }
        }
    }];
} catch (e) {
    // Si falla el parseo (es texto plano), limpiamos y enviamos
    return [{
        json: {
            Respuesta: {
                PayphoneUrl: text.replace(/[\\"]/g, '').trim(),
                ValorTotal: $('Input').first().json.MontoPago || 25,
                Status: "Success"
            }
        }
    }];
}

